final class AppState: ObservableObject {
    @Published var portfolio = Portfolio.sample
    @Published var orders: [TradeOrder] = []
    @Published var quotes: [String: Quote] = [:]
    @Published var selectedSymbol: String = "AAPL"
    @Published var orderQuantity: String = "1"
    @Published var orderType: OrderType = .market
    @Published var orderSide: OrderSide = .buy
    @Published var statusMessage: String = ""
    
    let apiClient = APIClient()
    let tradeService = TradeService()
    let marketDataService = MarketDataService()
    
    private var cancellables = Set<AnyCancellable>()
    
    init() {
        bindServices()
        Task {
            await refreshMarketData()
        }
    }
    
    private func bindServices() {
        marketDataService.quotesPublisher
            .receive(on: DispatchQueue.main)
            .sink { [weak self] quotes in
                for quote in quotes {
                    self?.quotes[quote.symbol] = quote
                }
            }
            .store(in: &cancellables)
    }
    
    func refreshMarketData() async {
        do {
            let symbols = portfolio.positions.map { $0.symbol } + [selectedSymbol]
            try await marketDataService.startStreaming(symbols: Array(Set(symbols)))
        } catch {
            statusMessage = "Market data unavailable"
        }
    }
    
    func placeOrder() {
        guard let quantity = Int(orderQuantity), quantity > 0 else {
            statusMessage = "Invalid quantity"
            return
        }
        
        let order = TradeOrder(
            id: UUID(),
            symbol: selectedSymbol,
            quantity: quantity,
            side: orderSide,
            type: orderType,
            status: .pending,
            timestamp: Date(),
            price: quotes[selectedSymbol]?.price
        )
        
        Task {
            do {
                let executed = try await tradeService.execute(order: order, portfolio: &portfolio, quote: quotes[selectedSymbol])
                await MainActor.run {
                    self.orders.insert(executed, at: 0)
                    self.statusMessage = "Order executed"
                }
            } catch {
                await MainActor.run {
                    self.statusMessage = "Order failed: \(error.localizedDescription)"
                }
            }
        }
    }
}

