struct Portfolio: Codable {
    var cash: Double
    var positions: [Position]
    
    var totalEquity: Double {
        cash + positions.reduce(0) { $0 + $1.marketValue }
    }
    
    static let sample = Portfolio(
        cash: 25000,
        positions: [
            Position(symbol: "AAPL", quantity: 20, averageCost: 180.0, lastPrice: 185.0),
            Position(symbol: "MSFT", quantity: 10, averageCost: 390.0, lastPrice: 402.0)
        ]
    )
}

struct Position: Identifiable, Codable {
    var id: String { symbol }
    let symbol: String
    var quantity: Int
    var averageCost: Double
    var lastPrice: Double
    
    var marketValue: Double { Double(quantity) * lastPrice }
}

struct Quote: Codable {
    let symbol: String
    let price: Double
    let bid: Double
    let ask: Double
    let timestamp: Date
}

enum OrderSide: String, CaseIterable, Codable {
    case buy = "Buy"
    case sell = "Sell"
}

enum OrderType: String, CaseIterable, Codable {
    case market = "Market"
    case limit = "Limit"
}

enum OrderStatus: String, Codable {
    case pending = "Pending"
    case filled = "Filled"
    case rejected = "Rejected"
}

struct TradeOrder: Identifiable, Codable {
    let id: UUID
    let symbol: String
    let quantity: Int
    let side: OrderSide
    let type: OrderType
    var status: OrderStatus
    let timestamp: Date
    let price: Double?
}

final class TradeService {
    enum TradeError: Error {
        case insufficientFunds
        case insufficientShares
        case missingQuote
    }
    
    func execute(order: TradeOrder, portfolio: inout Portfolio, quote: Quote?) async throws -> TradeOrder {
        guard let quote else { throw TradeError.missingQuote }
        var executed = order
        let executionPrice = order.type == .market ? quote.ask : (order.price ?? quote.price)
        let total = executionPrice * Double(order.quantity)
        
        switch order.side {
        case .buy:
            guard portfolio.cash >= total else { throw TradeError.insufficientFunds }
            portfolio.cash -= total
            if let index = portfolio.positions.firstIndex(where: { $0.symbol == order.symbol }) {
                let existing = portfolio.positions[index]
                let newQty = existing.quantity + order.quantity
                let newAvg = ((existing.averageCost * Double(existing.quantity)) + total) / Double(newQty)
                portfolio.positions[index].quantity = newQty
                portfolio.positions[index].averageCost = newAvg
                portfolio.positions[index].lastPrice = quote.price
            } else {
                portfolio.positions.append(Position(symbol: order.symbol, quantity: order.quantity, averageCost: executionPrice, lastPrice: quote.price))
            }
        case .sell:
            guard let index = portfolio.positions.firstIndex(where: { $0.symbol == order.symbol }),
                  portfolio.positions[index].quantity >= order.quantity else { throw TradeError.insufficientShares }
            portfolio.positions[index].quantity -= order.quantity
            portfolio.cash += total
            portfolio.positions[index].lastPrice = quote.price
            if portfolio.positions[index].quantity == 0 {
                portfolio.positions.remove(at: index)
            }
        }
        
        executed.status = .filled
        return executed
    }
}

final class MarketDataService {
    let quotesPublisher = PassthroughSubject<[Quote], Never>()
    private var timer: Timer?
    
    func startStreaming(symbols: [String]) async throws {
        timer?.invalidate()
        timer = Timer.scheduledTimer(withTimeInterval: 1.5, repeats: true) { [weak self] _ in
            guard let self else { return }
            let quotes = symbols.map { symbol in
                let base = Double.random(in: 50...500)
                return Quote(symbol: symbol.uppercased(), price: base, bid: base - 0.05, ask: base + 0.05, timestamp: Date())
            }
            self.quotesPublisher.send(quotes)
        }
        RunLoop.main.add(timer!, forMode: .common)
    }
}

final class APIClient {
    private let session: URLSession
    private let baseURL = URL(string: "https://api.yourbroker.com")!
    
    init(session: URLSession = .shared) {
        self.session = session
    }
    
    func send<T: Decodable>(_ request: URLRequest) async throws -> T {
        let (data, response) = try await session.data(for: request)
        guard let http = response as? HTTPURLResponse, 200..<300 ~= http.statusCode else {
            throw URLError(.badServerResponse)
        }
        return try JSONDecoder().decode(T.self, from: data)
    }
    
    func authenticatedRequest(path: String, method: String = "GET", body: Data? = nil) -> URLRequest {
        var request = URLRequest(url: baseURL.appendingPathComponent(path))
        request.httpMethod = method
        request.httpBody = body
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        if let token = KeychainService.shared.token {
            request.setValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
        }
        return request
    }
}

final class KeychainService {
    static let shared = KeychainService()
    private let service = "com.example.tradingapp"
    private let account = "apiToken"
    
    var token: String? {
        get {
            let query: [String: Any] = [
                kSecClass as String: kSecClassGenericPassword,
                kSecAttrService as String: service,
                kSecAttrAccount as String: account,
                kSecReturnData as String: true,
                kSecMatchLimit as String: kSecMatchLimitOne
            ]
            var result: CFTypeRef?
            let status = SecItemCopyMatching(query as CFDictionary, &result)
            guard status == errSecSuccess, let data = result as? Data else { return nil }
            return String(data: data, encoding: .utf8)
        }
        set {
            let data = Data((newValue ?? "").utf8)
            let query: [String: Any] = [
                kSecClass as String: kSecClassGenericPassword,
                kSecAttrService as String: service,
                kSecAttrAccount as String: account
            ]
            SecItemDelete(query as CFDictionary)
            let attributes: [String: Any] = query.merging([kSecValueData as String: data]) { $1 }
            SecItemAdd(attributes as CFDictionary, nil)
        }
    }
}

